-- CNB Primaria - Comunicación y Lenguaje L 1 - Primer Grado
-- Fuente: https://cnbguatemala.org/wiki/Dosificaci%C3%B3n_de_los_aprendizajes_-_%C3%81rea_de_Comunicaci%C3%B3n_y_Lenguaje_L_1_-_Primer_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primer Grado', 'Comunicación y Lenguaje L 1', '1. Escucha a su interlocutor o interlocutora demostrando respeto y comprensión del mensaje por medio de gestos y movimientos. 1.1. Demuestra respeto hacia las prácticas comunicativas de otras personas y culturas. 1.2. Demuestra comprensión de lo que escucha. 1.3. Identifica los sonidos del habla y percibe sus semejanzas y diferencias en los mensajes que escucha. (Conciencia fonológica).', ARRAY['1.1.1. Demostración de respeto hacia la persona que habla: posición del cuerpo, gestos (miradas, movimientos de la cara, señales con las manos, con los hombros, entre otros.), silencio en el momento en que se usa la palabra.', '1.1.2. Práctica de normas de cortesía en conversaciones, diálogos y discusiones (esperar turno para hablar, hablar con el tono de voz apropiado, utilizar el vocabulario preciso, evitar el uso de sobrenombres, clasificadores personales, entre otros).', '1.1.3. Demostración de respeto hacia gestos y prácticas comunicativas comunes en otros idiomas y culturas del país.', '1.2.1. Seguimiento de instrucciones orales de hasta tres eventos.', '1.2.2. Interpretación de rimas, cuentos, poemas, canciones, entre otros por medio de gestos y movimientos corporales.', '1.2.3. Comparación de las características de los personajes que protagonizan los cuentos en las narraciones que escuchan.', '1.2.4. Expresión de opiniones sobre el texto que se lee o escucha (Comprensión crítica).', '1.3.1. Identificación de similitudes y diferencias entre los sonidos en el lenguaje que escucha.', '1.3.2. Percepción auditiva de las sílabas que integran las palabras clave en los mensajes que escucha.', '1.3.3. Reconocimiento de los fonemas como las unidades sonoras que conforman las palabras que escucha.', '1.3.4. Identificación de palabras que riman.', '1.3.5. Percepción auditiva del fonema inicial y del fonema final en las palabras que escucha.', '1.3.6 Reconocimiento de la diferencia que representa la sustitución de una letra en palabras determinadas en cuanto a sonido y significación (luna - lana - lona; puma - fuma - bruma; casa - caza - caña - cana).']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '2. Expresa oralmente sus opiniones, sentimientos, emociones y experiencias de su contexto familiar y escolar. 2.1. Utiliza diferentes estrategias para expresarse. 2.2. Narra o describe oralmente, situaciones reales o ficticias.', ARRAY['2.1.1. Organización de la información necesaria dentro y fuera del aula.', '2.1.2. Estructuración mental de la información solicitada antes de verbalizar su respuesta.', '2.1.3. Formulación de preguntas para solicitar información y de respuestas a preguntas que le plantean. (Entrevista)', '2.1.4. Emisión de opiniones personales al evaluar mensajes escuchados', '2.1.5. Iniciación y desarrollo de conversaciones dentro y fuera del aula.', '2.1.6. Utilización de argumentos pertinentes para fundamentar una idea ante diferentes opiniones.', '2.2.1. Narración de experiencias propias o de otros y otras.', '2.2.2. Narración de cuentos, leyendas, poemas y otros tipos de textos escuchados.', '2.2.3. Narración de mensajes orales escuchados, resumiendo o aclarando la información.', '2.2.4. Descripción de experiencias utilizando oraciones y pronunciando claramente.', '2.2.5. Reproducción de juegos verbales: rimas, trabalenguas, retahilas.', '2.2.6. Reproducción oral de lo escuchado recitándolo o parafraseándolo.']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '3. Utiliza el lenguaje no verbal como auxiliar de la comunicación. 3.1. Utiliza gestos y movimientos corporales como apoyo en su expresión oral. 3.2. Utiliza sonidos onomatopéyicos para reforzar sus mensajes.', ARRAY['3.1.1. Comunicación de estados de ánimo por medio de gestos.', '3.1.2. Descripción de las características de objetos y de personas por medio de gestos.', '3.1.3. Manifestación del conocimiento de su esquema corporal por medio de gestos.', '3.1.4. Asociación de los movimientos corporales con las palabras que indican la dirección de su desplazamiento en el espacio: arriba, abajo, adelante, atrás, izquierda, derecha, entre otras.', '3.1.5. Utilización de gestos y movimientos corporales para indicar la posición de objetos en el espacio y la relación que existe ellos: encima, debajo, adelante atrás, lejos, cerca, izquierda, derecha, al frente, detrás de, entre otros.', '3.1.6. Representación de cuentos, juegos e historietas por medio del lenguaje corporal, de la danza y del teatro.', '3.2.1. Utilización de palabras cuya pronunciación imita el sonido de aquello que describe: "pum", "clic", "crash", entre otras.', '3.2.2. Utilización de palabras que imitan el sonido producido por animales: "miau", "guau", "pío, pío", "cuac, cuac", entre otras.', '3.2.3. Utilización de palabras que imitan el sonido producido por instrumentos musicales: "chin", "plin", "pom, pom, pom", entre otros.']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '4. Utiliza la lectura para recrearse y asimilar información. 4.1. Interpreta el significado de imágenes, signos, símbolos y señales del entorno y los relaciona con textos escritos. 4.2. Lee textos de diferente contenido demostrando comprensión de los mismos a un nivel literal. 4.3. Lee textos de diferente. 4.4. Emite opinión con respecto al contenido de los textos que lee y analiza. 4.5. Lee con un propósito definido: recrearse u obtener información.', ARRAY['4.1.1. Identificación de signos, símbolos, íconos y señales del entorno inmediato.', '4.1.2. Diferenciación entre ilustraciones, señales y texto escrito.', '4.1.3. Asociación de ilustraciones con textos cortos que las describen.', '4.1.4. Identificación de las partes de un libro: portada, título, subtítulos, entre otros.', '4.1.5. Sucesión cronológica o temporal de eventos en una historia: ordenamiento de gráficas o ilustraciones.', '4.1.6. Predicción sobre el tema de una historia a partir de signos, símbolos o ilustraciones.', '4.2.1. Asociación entre objetos del entorno y la o las palabras que los nombran.', '4.2.2. Establecimiento de la relación símbolo escrito (grafema) y sonido (fonema)', '4.2.3. Asociación del fonema con la letra respectiva (por lo menos las vocales y 6 consonantes).', '4.2.4. Asociación del fonemas con las letras del alfabeto (por lo menos las vocales y 12 consonantes).', '4.2.5. Asociación de fonemas con las letras del alfabeto (por lo menos las vocales y 20 consonantes).', '4.2.6. Lectura de palabras, oraciones e historias con dominio de las vocales y por lo menos 6 consonantes, y con dominio de las vocales y por lo menos 12 consonantes.', '4.2.7. Lectura de las palabras que nombran números de uno a diez en español y de uno a veinte en idiomas mayas.', '4.2.8 Formulación de preguntas y elaboración de respuestas a nivel literal sobre la lectura.', '4.2.9. Seguimiento de instrucciones escritas, con no más de tres acciones.', '4.3.1. Identificación del orden de los eventos en las historias o material informativo que lee.', '4.3.2 Identificación de los detalles importantes en un texto: personajes principales y secundarios, hechos, objetos, entre otros.', '4.3.3. Comparación y contraste entre personajes y entre lugares.', '4.3.4. Diferenciación entre el inicio y el final de la historia', '4.3.5. Identificación de la idea principal de un texto corto.', '4.3.6. Reconocimiento de palabras que pueden sustituir a otras en una historia sin cambiar el significado de la misma.', '4.4.1. Identificación del problema y de las posibles soluciones en los textos que lee.', '4.4.2. Emisión de comentarios de gusto o disgusto sobre los textos que lee.', '4.4.3. Elaboración de conclusiones tomando en cuenta los acontecimientos principales en la historia.', '4.5.1. Distinción entre fantasía y realidad.', '4.5.2. Lectura de diversos tipos de texto.', '4.5.3. Distinción entre un cuento y una noticia.', '4.5.4. Diferenciación entre la estructura de los cuentos y las cartas.', '4.5.5. Lectura con diferentes propósitos: como recreación (rimas, retahilas, poemas y cuentos), para determinar la ubicación en el tiempo: reloj y calendarios - gregoriano y cholq''ij-, con diferentes intenciones: compras, inventarios, almacenamiento.', '4.5.6. Localización de información específica en diversos medios impresos: libros, revistas, periódicos, entre otros.']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '5. Se expresa por escrito utilizando los trazos de las letras y los signos de puntuación. 5.1. Aplica los principios de la caligrafía al expresarse por escrito. 5.2. Utiliza principios de gramática al expresarse por escrito.', ARRAY['5.1.1. Aplicación de los principios de la caligrafía: posición del cuerpo, empuñadura del lápiz, posición del papel, trazo de letras, entre otros.', '5.1.2. Observación de la direccionalidad de las letras al escribir (rasgos que ocupan el espacio principal, rasgos que se extienden hacia arriba y hacia abajo).', '5.1.3. Observación de la linealidad al escribir (dirección izquierda - derecha).', '5.1.4. Observación de los espacios entre las letras y las palabras, márgenes.', '5.1.5. Utilización de los elementos convencionales para escribir: lugar de las letras y palabras sobre el renglón.', '5.2.1. Diferenciación entre letras mayúsculas y minúsculas.', '5.2.2. Utilización de mayúscula inicial en las oraciones que escribe.', '5.2.3. Uso del punto al final de las oraciones que escribe.', '5.2.4. Formulación de oraciones que reflejen concordancia de género y de número según la lengua materna.', '5.2.5. Formulación de párrafos que reflejen orden lógico de las ideas: inicio, desarrollo y desenlace.']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '6. Utiliza nociones de la estructura de las palabras al expresar sus ideas. 6.1. Identifica las sílabas que conforman las palabras y percibe sus semejanzas y diferencias. (Conciencia silábica). 6.2. Forma nuevas palabras con base en la estructura del idioma.', ARRAY['6.1.1. Identificación de las palabras que integran una oración.', '6.1.2. Identificación oral de las sílabas que conforman palabras específicas.', '6.1.3. Separación oral de palabras en sílabas.', '6.1.4. Reconocimiento de sílabas directas, indirectas y cerradas en palabras conocidas.', '6.1.5. Diferenciación entre sílabas directas y cerradas.', '6.2.1. Indicación del número de sílabas que conforman una palabra.', '6.2.2. Formación de palabras nuevas tomando como referencia palabras conocidas', '6.2.3. Formación de palabras nuevas uniendo sílabas de palabras conocidas.', '6.2.4. Formación del plural de las palabras en español agregando "s" o "es"; en K''iche'' "ab" o "ib"; en Q''eqchi'' "eb"; entre otros.', '6.2.5. Formación de familias de palabras agregando a la raíz el afijo que forma el diminutivo y el aumentativo de palabras conocidas (sufijo en español; prefijos en idiomas mayas).']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '7. Utiliza vocabulario propio de su lengua materna abundante y pertinente en su interacción con las y los demás. 7.1. Demuestra comprensión del vocabulario que escucha. 7.2. Manifiesta interés por enriquecer su vocabulario con palabras y expresiones propias de su lengua materna. 7.3. Utiliza el vocabulario adquirido en diferentes situaciones al interactuar con otras personas.', ARRAY['7.1.1. Utilización de claves de contexto para identificar palabras nuevas.', '7.1.2. Utilización pertinente de palabras que se forman a partir de palabras conocidas.', '7.1.3. Utilización del vocabulario apropiado para describir características físicas (adjetivos), estados de ánimo, emociones, sensaciones y sentimientos.', '7.1.4. Análisis oral (deletreo) de palabras cuyo significado desconoce.', '7.1.5. Identificación de palabras que nombran (sustantivos: comunes y propios).', '7.1.6. Identificación de palabras con significado igual o parecido (sinónimos).', '7.1.7. Identificación de palabras con significado opuesto (antónimos).', '7.2.1. Interpretación del significado de palabras desconocidas asociándolas con el vocabulario que posee.', '7.2.2. Uso del contexto para identificar el significado de palabras nuevas.', '7.2.3 Utilización de vocabulario y expresiones propias de su lengua materna.', '7.3.1. Descripción de estados de ánimo utilizando las palabras apropiadas y la entonación precisa.', '7.3.2. Incorporación, al vocabulario básico, de palabras que escucha en su interacción con otras personas y que son apropiadas a la situación.', '7.3.3. Introducción de palabras nuevas en los textos que escribe.', '7.3.4. Utilización del vocabulario adecuado según el tipo de texto que escribe.']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '8. Expresa por escrito sus sentimientos, emociones pensamientos y experiencias. 8.1. Expresa por escrito su percepción de las características de personas, objetos, animales y plantas. 8.2. Narra experiencias personales o elementos de lecturas realizadas.', ARRAY['8.1.1. Elaboración de dibujos para expresar ideas con respecto a personas, objetos, animales y plantas', '8.1.2. Descripción de características de los personajes incluidos en sus dibujos.', '8.2.1. Representación de ideas o contenido de un cuento por medio de dibujos en secuencia.', '8.2.2. Selección de las palabras apropiadas según los dibujos elaborados alrededor de un tema.', '8.2.3. Elaboración de imágenes para ilustrar textos que redacta.', '8.2.4. Redacción individual de narraciones cortas, anéctotas y chistes acerca de eventos de la vida cotidiana.', '8.2.5. Organización de ideas y respeto a las normas del idioma al elaborar narraciones cortas (dominio de, por lo menos, 20 consonantes y las vocales).', '8.2.6. Formulación de párrafos sencillos que reflejen concordancia entre artículos, sustantivos y adjetivos (sin mencionar la terminología).']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '9. Utiliza el lenguaje oral y escrito como instrumento para afianzar su aprendizaje. 9.1. Utiliza elementos del lenguaje oral y escrito en la reafirmación de su aprendizaje. 9.2. Utiliza elementos del lenguaje oral y escrito en el manejo de la información que proporcionan los medios de comunicación.', ARRAY['9.1.1. Expresión de ideas, sentimientos y emociones formando párrafos según las reglas del idioma.', '9.1.2. Utilización de la información obtenida de diferentes medios en la formulación de preguntas y mostrar sus puntos de vista.', '9.1.3 Revisión de textos que produce para corregirlos y asegurar que puedan ser comprendidos por otras personas.', '9.2.1. Utilización de la biblioteca del aula en la documentación de sus trabajos.', '9.2.2. Selección de los recursos existentes y de la información pertinente para estructurar el periódico mural.']);
